/**
 * Парсит текст с AI Agent для всех строк
 * Поддерживает Markdown обертку ```json ... ```
 */

function extractJson(raw) {
  if (typeof raw !== 'string') return raw;
  let s = raw.trim();
  s = s.replace(/^```(\w+)?\s*/,'').replace(/```$/,'').trim();
  const start = s.search(/[{[]/);
  const end = Math.max(s.lastIndexOf('}'), s.lastIndexOf(']'));
  if (start !== -1 && end > start) s = s.slice(start, end + 1);
  return s;
}

// Берем все items из предыдущей ноды
const allItems = $items();

const parsedItems = allItems.map(item => {
  const rawText = item.json.text || item.json.output;
  let parsed;
  try {
    parsed = JSON.parse(extractJson(rawText));
  } catch (e) {
    parsed = { error: e.message, raw: rawText };
  }
  return parsed;
});

// Объединяем все parsed объекты в один массив
const merged = [].concat(...parsedItems);

return [{ json: { allData: merged } }];

// Берем все items из предыдущей ноды
const items = $items();

// Собираем все allData из каждого item
const merged = items.reduce((acc, item) => {
  if (item.json.allData && Array.isArray(item.json.allData)) {
    acc.push(...item.json.allData); // разворачиваем массив allData
  } else if (item.json.allData) {
    acc.push(item.json.allData); // если allData один объект
  }
  return acc;
}, []);

// Возвращаем один item с массивом всех объектов
return [{ json: { allData: merged } }];

// Берем все items из потока
const items = $items();

// Собираем все объекты из всех items
const merged = items.reduce((acc, item) => {
  if (item.json.allData && Array.isArray(item.json.allData)) {
    acc.push(...item.json.allData);
  } else if (item.json.allData) {
    acc.push(item.json.allData);
  }
  return acc;
}, []);

// Оставляем только type и credentials
const result = merged.map(obj => ({
  type: obj.type,
  credentials: obj.credentials ? { id: obj.credentials.id, name: obj.credentials.name } : null
}));

// Возвращаем каждый объект как отдельный item (или один массив, если нужно)
return result.map(obj => ({ json: obj }));

// Массив с объектами типа { type, credentials: { id, name } }
const nodes = $items().map(item => item.json);

// Используем Map для фильтрации дубликатов по type + credential id
const uniqueMap = new Map();

nodes.forEach(node => {
  const key = `${node.type}__${node.credentials?.id || ''}`;
  if (!uniqueMap.has(key)) {
    uniqueMap.set(key, node);
  }
});

// Получаем массив уникальных объектов
const uniqueNodes = Array.from(uniqueMap.values());

return uniqueNodes.map(node => ({ json: node }));

