/**
 * Function Node
 * Достаёт JSON из текста или markdown
 */

function extractJson(raw) {
  if (typeof raw !== 'string') return raw;

  // убираем обёртку ```json ... ```
  let s = raw.trim();
  s = s.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();

  // берём только от первой { до последней }
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start !== -1 && end > start) {
    s = s.slice(start, end + 1);
  }

  return s;
}

const raw = $json.output || $json.text || ''; // текст из предыдущей ноды
let parsed;

try {
  parsed = JSON.parse(extractJson(raw));
} catch (e) {
  throw new Error('Не удалось распарсить JSON: ' + e.message);
}

return [{ json: parsed }];

/**
 * Function Node
 * Приводит JSON от AI к валидному workflowObject
 */

function normalizeWorkflow(input) {
  if (!input || typeof input !== 'object') {
    throw new Error('Ожидался объект');
  }

  // Базовый каркас воркфлоу
  const workflow = {
    name: input.name || 'Generated Workflow',
    nodes: [],
    connections: {},
  };

  // Обработка нод
  (input.nodes || []).forEach((node, index) => {
    const cleanNode = {
      id: node.id || String(index + 1),
      name: node.name || `Node${index + 1}`,
      type: node.type || 'n8n-nodes-base.function',
      typeVersion: node.typeVersion || 1,
      position: node.position || [200 + index * 200, 300],
      parameters: node.parameters || {},
      credentials: node.credentials || {},
    };

    workflow.nodes.push(cleanNode);
  });

  // Обработка связей
  if (input.connections && Object.keys(input.connections).length > 0) {
    workflow.connections = input.connections;
  } else {
    // Если нет connections — строим линейные
    for (let i = 0; i < workflow.nodes.length - 1; i++) {
      const from = workflow.nodes[i].name;
      const to = workflow.nodes[i + 1].name;

      if (!workflow.connections[from]) {
        workflow.connections[from] = { main: [[]] };
      }
      workflow.connections[from].main[0].push({
        node: to,
        type: 'main',
        index: 0,
      });
    }
  }

  return workflow;
}

// Берём JSON от предыдущей ноды (AI Agent, например)
const raw = $json;

// Возвращаем готовый workflowObject
return [
  {
    json: {
      workflowObject: normalizeWorkflow(raw),
    },
  },
];

